#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

__kernel void benchmark_func(const class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);
  const size_t global_stride = get_global_size(0);
  const size_t local_stride = get_local_size(0);

#ifdef BLOCK_STRIDED
  const size_t stride = local_stride;
#else
  const size_t stride = global_stride;
#endif

  for (uint f = 0; f < (uint)FUSION_DEGREE; ++f) {
    size_t idx = gid + ((size_t)f * (size_t)ELEMENTS_PER_THREAD) * stride;

    for (uint e = 0; e < (uint)ELEMENTS_PER_THREAD; ++e, idx += stride) {
      class_T t = data[idx];

      for (uint it = 0; it < (uint)COMPUTE_ITERATIONS; ++it) {
        t = t * t + seed;
      }

      data[idx] = t;
    }
  }
}
